#include<cstdio>
using namespace std;

int main()
{
	int n,a[1001],maxn,mina,cha;
	scanf("%d",&n);
	scanf("%d",&a[1]);
	maxn=a[1];
	mina=a[1];
    for(int i=2;i<=n;i++)
    {
    	scanf("%d",&a[i]);
	    if(a[i]>maxn)
	    maxn=a[i];

	    if(a[i]<mina)
	    mina=a[i];
    }
    cha=maxn-mina;
    printf("%d",cha);
    return 0;
}
